-- 出库单号
select  DISTINCT VRECEIPTCODE as return_order,出库单号 as original_order_no,dd.storname as 库房,ch.invpinpai,ch.height,ch.width,ch.length,ch.invname,ch.invcode as 存货编码,nnumber as 数量
from nc5x.so_apply aa
join nc5x.so_apply_b bb
on aa.pk_apply = bb.pk_apply 
and aa.dr = 0 and bb.dr = 0  
left join nc5x.bd_stordoc dd
on bb.cbodywarehouseid = dd.pk_stordoc
left join (
select 
distinct 
hl.vreceiptcode  as 单据号,
js.vreceiptcode as 出库单号 
 from nc5x.so_squaredetail js
left join nc5x.so_sale hl
on js.csourcebillid = hl.csaleid
