LEFT join (
select ch.invpinpai,ch.height,ch.width,ch.length,ch.invname,ch.invcode,cg.pk_invmandoc,ch.unitweight,ch.unitvolume,
cg.refsaleprice as 批发售价
,cg.def5 as 代理价 
,cg.lowestprice   as 最低限价
from nc5x.bd_invmandoc cg
join nc5x.bd_invbasdoc ch
on cg.pk_invbasdoc = ch.pk_invbasdoc )ch
on bb.cinventoryid = ch.pk_invmandoc
where 单据号 is not null and  aa.dr = 0 and bb.dr = 0 and ch.width not in ('周边外设','礼品') and  length(ch.invcode)>5
union all 
--订单号
select  DISTINCT VRECEIPTCODE as return_order,VFIRSTCODE as original_order_no,dd.storname as 库房,ch.invpinpai,ch.height,ch.width,ch.length,ch.invname,ch.invcode,nnumber
from nc5x.so_apply aa
join nc5x.so_apply_b bb
on aa.pk_apply = bb.pk_apply 
and aa.dr = 0 and bb.dr = 0  
left join nc5x.bd_stordoc dd
on bb.cbodywarehouseid = dd.pk_stordoc
LEFT join (
select ch.invpinpai,ch.height,ch.width,ch.length,ch.invname,ch.invcode,cg.pk_invmandoc,ch.unitweight,ch.unitvolume,
cg.refsaleprice as 批发售价
,cg.def5 as 代理价 
,cg.lowestprice   as 最低限价
from nc5x.bd_invmandoc cg
join nc5x.bd_invbasdoc ch
on cg.pk_invbasdoc = ch.pk_invbasdoc )ch
on bb.cinventoryid = ch.pk_invmandoc

